def bump(kind, version="1.2.3"):
    major, minor, patch = map(int, version.split("."))
    if kind == "major":
        return f"{major+1}.0.0"
    if kind == "minor":
        return f"{major}.{minor+1}.0"
    return f"{major}.{minor}.{patch+1}"

print("breaking", bump("major"))
print("feature", bump("minor"))
print("fix", bump("patch"))

